struct Rectangle {
    var width: Double
    var height: Double

    // Computed Property
    var area: Double {
        return width * height
    }
}

var myRect = Rectangle(width: 5, height: 10)
print("Initial Area: \(myRect.area)")

myRect.width = 20
print("New Area: \(myRect.area)")
